module top_module(CLK, EN, TE, DATA, Q);input CLK, EN, TE;
  input [31:0] DATA;
  output reg [31:0] Q;

  wire unused_gated_clk;

  assign unused_gated_clk = (EN && !TE) ? CLK : 1'b0;

  always @(posedge unused_gated_clk) begin
    if (EN && !TE) begin
      Q <= DATA;
    end
  end

endmodule
